// Define your API in a `.dart` file — Pigeon generates Dart + Kotlin + Swift.

import 'package:pigeon/pigeon.dart';

@ConfigurePigeon(PigeonOptions(
  dartOut: 'lib/battery_api.dart',
  kotlinOut: 'android/app/src/main/kotlin/com/myapp/BatteryApi.kt',
  swiftOut: 'ios/Runner/BatteryApi.swift',
))

@HostApi()
abstract class BatteryHostApi {
  int getBatteryLevel();
}

// Then: `dart run pigeon --input pigeons/battery.dart`
// Both sides get typed method signatures, generated codecs, and null-safety.
// No more `invokeMethod<int>('getBatteryLevel')` strings — call
// BatteryHostApi().getBatteryLevel() directly.

